// // This module selects and modifies the input based on the selection signal.
// When sel=00, it outputs the lower two bits of the input followed by two ones.
// For sel=01, it performs a bitwise OR with the mask 1100, effectively setting the lower two bits to 1.
// With sel=10, it executes a bitwise AND with the mask 0011, clearing the lower two bits.
// Lastly, when sel=11, it applies a bitwise XOR with the mask 1010.
module top_module(
    input [3:0] in,
    input [1:0] sel,
    output reg [3:0] out
);always @(*) begin
    case(sel)
        2'b00: out = {in[3:2], 2'b00};
        2'b01: out = in & 4'b1100;
        2'b10: out = in | 4'b0011;
        2'b11: out = in ^ 4'b1010;
    endcase
end

endmodule

